import { useRef, useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { Send, Loader2, User, Mic, MicOff, ArrowLeft, SquarePen, Sparkles, Clock, Users, Utensils, Bookmark, Image } from "lucide-react";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { useProfile } from "@/hooks/useProfile";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import LocationPermissionDialog from "@/components/LocationPermissionDialog";
import ExternalLinkConfirmDialog from "@/components/ExternalLinkConfirmDialog";
import { openExternalUrl } from "@/lib/externalLinks";
import { useAuth } from "@/contexts/AuthContext";
import { Message, RecipeImageMap, extractRecipes, stripRecipeJson } from "@/hooks/useXiaoxiongChat";
import { useLoginRequired } from "@/hooks/useLoginRequired";
import { useSavedRecipes } from "@/hooks/useSavedRecipes";
import { AIRecipeSuggestion } from "@/hooks/useAIRecipe";
import SavedRecipeDetailDialog from "@/components/ai-recipe/SavedRecipeDetailDialog";

// TypeScript declarations for Web Speech API
interface SpeechRecognitionEvent extends Event {
  results: SpeechRecognitionResultList;
}

interface SpeechRecognitionErrorEvent extends Event {
  error: string;
}

interface SpeechRecognition extends EventTarget {
  lang: string;
  continuous: boolean;
  interimResults: boolean;
  onstart: ((this: SpeechRecognition, ev: Event) => void) | null;
  onresult: ((this: SpeechRecognition, ev: SpeechRecognitionEvent) => void) | null;
  onerror: ((this: SpeechRecognition, ev: SpeechRecognitionErrorEvent) => void) | null;
  onend: ((this: SpeechRecognition, ev: Event) => void) | null;
  start(): void;
  stop(): void;
}

declare global {
  interface Window {
    SpeechRecognition: new () => SpeechRecognition;
    webkitSpeechRecognition: new () => SpeechRecognition;
    webkit?: {
      messageHandlers: {
        VoiceBridge?: {
          postMessage: (message: string) => void;
        };
      };
    };
    VoiceBridge?: {
      postMessage: (message: string) => void;
    };
    onSpeechResult?: (text: string) => void;
  }
}

// Check for native voice bridge support
const hasNativeVoiceBridge = (): boolean => {
  try {
    return !!(
      (window.webkit?.messageHandlers?.VoiceBridge) || 
      window.VoiceBridge
    );
  } catch {
    return false;
  }
};

// Native voice bridge utility
const NativeVoice = {
  start: () => {
    try {
      const message = JSON.stringify({ action: "start" });
      if (window.webkit?.messageHandlers?.VoiceBridge) {
        window.webkit.messageHandlers.VoiceBridge.postMessage(message);
      } else if (window.VoiceBridge) {
        window.VoiceBridge.postMessage(message);
      }
    } catch (e) {
      console.warn("NativeVoice.start failed:", e);
    }
  },
  stop: () => {
    try {
      const message = JSON.stringify({ action: "stop" });
      if (window.webkit?.messageHandlers?.VoiceBridge) {
        window.webkit.messageHandlers.VoiceBridge.postMessage(message);
      } else if (window.VoiceBridge) {
        window.VoiceBridge.postMessage(message);
      }
    } catch (e) {
      console.warn("NativeVoice.stop failed:", e);
    }
  }
};

export interface XiaoxiongChatContentProps {
  messages: Message[];
  input: string;
  setInput: (value: string) => void;
  isLoading: boolean;
  isLoadingHistory?: boolean;
  showLocationDialog: boolean;
  setShowLocationDialog: (value: boolean) => void;
  pendingMessage: string | null;
  handleSubmit: () => void;
  handleKeyDown: (e: React.KeyboardEvent) => void;
  handleLocationConfirm: () => void;
  processMessage: (message: string) => void;
  setPendingMessage: (message: string | null) => void;
  onClose?: () => void;
  onClearChat?: () => void | Promise<void>;
  showBackButton?: boolean;
  showHeader?: boolean;
  className?: string;
  recipeImages?: RecipeImageMap;
}

const XiaoxiongChatContent = ({
  messages,
  input,
  setInput,
  isLoading,
  isLoadingHistory,
  showLocationDialog,
  setShowLocationDialog,
  pendingMessage,
  handleSubmit,
  handleKeyDown,
  handleLocationConfirm,
  processMessage,
  setPendingMessage,
  onClose,
  onClearChat,
  showBackButton = false,
  showHeader = true,
  className,
  recipeImages = {},
}: XiaoxiongChatContentProps) => {
  const { i18n, t } = useTranslation();
  const navigate = useNavigate();
  const { user } = useAuth();
  const siteSettingsResult = useSiteSettings();
  const { data: profile } = useProfile();
  const settings = siteSettingsResult?.settings;
  const { requireLogin } = useLoginRequired();
  const { saveRecipe, isSaving, savedRecipes } = useSavedRecipes();
  const logoUrl = settings?.logo_url;
  const userAvatarUrl = profile?.avatar_url;
  
  const [isListening, setIsListening] = useState(false);
  const [speechSupported, setSpeechSupported] = useState(false);
  const [nativeVoiceSupported, setNativeVoiceSupported] = useState(false);
  const [externalLinkDialogOpen, setExternalLinkDialogOpen] = useState(false);
  const [pendingExternalLink, setPendingExternalLink] = useState<string | null>(null);
  const [previewRecipe, setPreviewRecipe] = useState<AIRecipeSuggestion | null>(null);
  const [previewOpen, setPreviewOpen] = useState(false);
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);
  const [savedRecipeNames, setSavedRecipeNames] = useState<Set<string>>(new Set());
  
  const scrollAreaRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const isRecipeSaved = (recipe: AIRecipeSuggestion) => {
    return savedRecipeNames.has(recipe.recipe_name) ||
      savedRecipes.some(s => s.recipe_name === recipe.recipe_name);
  };

  const handleSaveRecipe = async (recipe: AIRecipeSuggestion) => {
    if (!requireLogin()) return;
    if (isRecipeSaved(recipe)) return;
    await saveRecipe(recipe);
    setSavedRecipeNames(prev => new Set(prev).add(recipe.recipe_name));
  };

  const handleViewRecipe = (recipe: AIRecipeSuggestion, messageId: string) => {
    const imgState = recipeImages[messageId]?.[recipe.recipe_name];
    setPreviewImageUrl(imgState?.url ?? null);
    setPreviewRecipe(recipe);
    setPreviewOpen(true);
  };

  // Check for speech recognition support
  useEffect(() => {
    try {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      setSpeechSupported(!!SpeechRecognition);
      setNativeVoiceSupported(hasNativeVoiceBridge());
    } catch {
      setSpeechSupported(false);
      setNativeVoiceSupported(false);
    }
    
    window.onSpeechResult = (text: string) => {
      setInput(text);
      setIsListening(false);
    };
    
    return () => {
      window.onSpeechResult = undefined;
    };
  }, [setInput]);

  // Auto scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Cleanup speech recognition
  useEffect(() => {
    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, []);

  const shouldShowVoiceInput = (): boolean => {
    return speechSupported || nativeVoiceSupported;
  };

  const startListening = () => {
    if (nativeVoiceSupported) {
      NativeVoice.start();
      setIsListening(true);
      return;
    }

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }

    const recognition = new SpeechRecognition();
    recognitionRef.current = recognition;

    const langMap: Record<string, string> = {
      zh: "zh-CN",
      en: "en-US",
      pt: "pt-BR",
    };
    recognition.lang = langMap[i18n.language] || "zh-CN";
    recognition.continuous = false;
    recognition.interimResults = true;

    recognition.onstart = () => setIsListening(true);
    recognition.onresult = (event) => {
      const transcript = Array.from(event.results)
        .map((result) => result[0].transcript)
        .join("");
      setInput(transcript);
    };
    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => setIsListening(false);
    recognition.start();
  };

  const stopListening = () => {
    if (nativeVoiceSupported) {
      NativeVoice.stop();
      setIsListening(false);
      return;
    }
    
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  };

  const toggleListening = () => {
    if (isListening) {
      stopListening();
    } else {
      startListening();
    }
  };

  const handleLinkClick = (href: string) => {
    onClose?.();
    navigate(href);
  };

  const handleExternalLinkClick = (url: string) => {
    setPendingExternalLink(url);
    setExternalLinkDialogOpen(true);
  };

  const confirmExternalLink = () => {
    if (pendingExternalLink) {
      openExternalUrl(pendingExternalLink);
    }
    setExternalLinkDialogOpen(false);
    setPendingExternalLink(null);
  };

  const handleClearAndNewChat = () => {
    const confirmed = window.confirm(t("aiRecipe.newChatConfirm", "开始新对话将清除当前聊天记录，确定吗？"));
    if (!confirmed) return;

    try {
      void Promise.resolve(onClearChat?.()).catch((error) => {
        console.error("Clear chat failed:", error);
      });
    } catch (error) {
      console.error("Clear chat failed:", error);
    }
  };

  // Parse text with links
  const parseTextWithLinks = (text: string): JSX.Element[] => {
    const linkRegex = /\[([^\]]+)\]\(([^)]+)\)/g;
    const parts: JSX.Element[] = [];
    let lastIndex = 0;
    let match;
    let keyIndex = 0;

    while ((match = linkRegex.exec(text)) !== null) {
      if (match.index > lastIndex) {
        parts.push(<span key={keyIndex++}>{text.slice(lastIndex, match.index)}</span>);
      }

      const linkText = match[1];
      const href = match[2];

      if (href.startsWith("/")) {
        parts.push(
          <button
            key={keyIndex++}
            onClick={() => handleLinkClick(href)}
            className="text-primary hover:underline font-medium cursor-pointer"
          >
            {linkText}
          </button>
        );
      } else if (href.startsWith("!external:")) {
        const actualUrl = href.slice("!external:".length);
        parts.push(
          <button
            key={keyIndex++}
            onClick={() => handleExternalLinkClick(actualUrl)}
            className="text-primary hover:underline font-medium cursor-pointer"
          >
            {linkText}
          </button>
        );
      } else if (href.startsWith("http://") || href.startsWith("https://")) {
        parts.push(
          <button
            key={keyIndex++}
            onClick={() => handleExternalLinkClick(href)}
            className="text-primary hover:underline font-medium cursor-pointer"
          >
            {linkText}
          </button>
        );
      } else {
        parts.push(
          <a
            key={keyIndex++}
            href={href}
            target="_blank"
            rel="noopener noreferrer"
            className="text-primary hover:underline font-medium"
          >
            {linkText}
          </a>
        );
      }

      lastIndex = match.index + match[0].length;
    }

    if (lastIndex < text.length) {
      parts.push(<span key={keyIndex++}>{text.slice(lastIndex)}</span>);
    }

    return parts.length > 0 ? parts : [<span key="0">{text}</span>];
  };

  const removeBoldMarkers = (text: string): string => {
    return text.replace(/\*\*(.*?)\*\*/g, '$1');
  };

  const truncateText = (text: string, maxLength: number = 20): string => {
    if (text.length <= maxLength) return text;
    return text.slice(0, maxLength) + '...';
  };

  const renderTable = (tableLines: string[], key: number) => {
    const parseRow = (line: string) =>
      line
        .split("|")
        .slice(1, -1)
        .map((cell) => removeBoldMarkers(cell.trim()));

    const headers = parseRow(tableLines[0]);
    const rows = tableLines.slice(2).map(parseRow);

    return (
      <div key={key} className="overflow-x-auto my-2 max-w-full">
        <table className="w-full text-xs border border-border rounded-md overflow-hidden table-fixed">
          <thead className="bg-muted/60">
            <tr>
              {headers.map((header, i) => (
                <th
                  key={i}
                  className="px-2 py-2 text-left font-semibold border-b border-border truncate max-w-[100px]"
                  title={header}
                >
                  {parseTextWithLinks(truncateText(header, 15))}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.map((row, rowIndex) => (
              <tr
                key={rowIndex}
                className="border-b border-border last:border-0 hover:bg-muted/30 transition-colors"
              >
                {row.map((cell, cellIndex) => (
                  <td 
                    key={cellIndex} 
                    className="px-2 py-2 truncate max-w-[100px]"
                    title={cell}
                  >
                    {parseTextWithLinks(truncateText(cell, 18))}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const renderMarkdown = (content: string) => {
    const lines = content.split("\n");
    const elements: JSX.Element[] = [];
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];

      if (line.trim().startsWith("|") && line.split("|").length > 2) {
        const tableLines: string[] = [];
        while (i < lines.length && lines[i].trim().startsWith("|")) {
          tableLines.push(lines[i]);
          i++;
        }
        if (tableLines.length >= 2) {
          elements.push(renderTable(tableLines, elements.length));
        }
        continue;
      }

      if (line.startsWith("### ")) {
        elements.push(
          <h3 key={elements.length} className="text-base font-semibold mt-3 mb-1">
            {parseTextWithLinks(line.slice(4))}
          </h3>
        );
      } else if (line.startsWith("## ")) {
        elements.push(
          <h2 key={elements.length} className="text-lg font-bold mt-4 mb-2">
            {parseTextWithLinks(line.slice(3))}
          </h2>
        );
      } else if (line.startsWith("# ")) {
        elements.push(
          <h1 key={elements.length} className="text-xl font-bold mt-4 mb-2">
            {parseTextWithLinks(line.slice(2))}
          </h1>
        );
      } else if (line.includes("**")) {
        const parts = line.split(/\*\*(.*?)\*\*/g);
        elements.push(
          <p key={elements.length} className="mb-1 leading-relaxed">
            {parts.map((part, idx) =>
              idx % 2 === 1 ? (
                <strong key={idx} className="font-semibold">
                  {parseTextWithLinks(part)}
                </strong>
              ) : (
                parseTextWithLinks(part)
              )
            )}
          </p>
        );
      } else if (line.startsWith("- ") || line.startsWith("* ")) {
        elements.push(
          <li key={elements.length} className="ml-4 mb-0.5 list-disc">
            {parseTextWithLinks(line.slice(2))}
          </li>
        );
      } else if (/^\d+\.\s/.test(line)) {
        elements.push(
          <li key={elements.length} className="ml-4 mb-0.5 list-decimal">
            {parseTextWithLinks(line.replace(/^\d+\.\s/, ""))}
          </li>
        );
      } else if (line.match(/^[-*_]{3,}$/)) {
        elements.push(<hr key={elements.length} className="my-3 border-border" />);
      } else if (line.trim() === "") {
        elements.push(<div key={elements.length} className="h-1" />);
      } else {
        elements.push(
          <p key={elements.length} className="mb-1 leading-relaxed">
            {parseTextWithLinks(line)}
          </p>
        );
      }

      i++;
    }

    return elements;
  };

  const getTitle = () => {
    if (i18n.language === "zh") return "小熊AI助手";
    if (i18n.language === "pt") return "Assistente IA Xiaoxiong";
    return "Xiaoxiong AI Assistant";
  };

  const getPlaceholder = () => {
    const placeholders: Record<string, string> = {
      zh: "告诉小熊，你想吃什么...",
      en: "Tell Xiaoxiong what you want to eat...",
      pt: "Diga ao Xiaoxiong o que você quer comer...",
      es: "Dile a Xiaoxiong qué quieres comer...",
      fr: "Dites à Xiaoxiong ce que vous voulez manger...",
      de: "Sag Xiaoxiong, was du essen möchtest...",
      it: "Dì a Xiaoxiong cosa vuoi mangiare...",
      ja: "小熊に食べたいものを教えてください...",
      ko: "샤오슝에게 먹고 싶은 것을 알려주세요...",
      ar: "أخبر شاوشيونغ بما تريد أن تأكل...",
      ru: "Скажите Сяосюну, что вы хотите поесть...",
    };
    return placeholders[i18n.language] || placeholders.en;
  };

  const getWelcomeMessage = () => {
    const welcomes: Record<string, string> = {
      zh: "你好，我是小熊，我来帮你推荐餐厅；比如：「我附近的寿司餐厅」",
      en: "Hi, I'm Xiaoxiong, I'll help you find restaurants; for example: \"sushi restaurants near me\"",
      pt: "Olá, eu sou o Xiaoxiong, vou te ajudar a encontrar restaurantes; por exemplo: 「restaurantes de sushi perto de mim」",
      es: "Hola, soy Xiaoxiong, te ayudaré a encontrar restaurantes; por ejemplo: \"restaurantes de sushi cerca de mí\"",
      fr: "Bonjour, je suis Xiaoxiong, je vous aide à trouver des restaurants ; par exemple : « restaurants de sushi près de moi »",
      de: 'Hallo, ich bin Xiaoxiong, ich helfe dir Restaurants zu finden; zum Beispiel: „Sushi-Restaurants in meiner Nähe"',
      it: "Ciao, sono Xiaoxiong, ti aiuterò a trovare ristoranti; ad esempio: \"ristoranti di sushi vicino a me\"",
      ja: "こんにちは、小熊です。レストラン探しをお手伝いします。例：「近くの寿司レストラン」",
      ko: "안녕하세요, 샤오슝입니다. 레스토랑을 찾아드릴게요. 예: \"근처 스시 레스토랑\"",
      ar: "مرحبًا، أنا شاوشيونغ، سأساعدك في العثور على مطاعم؛ مثال: \"مطاعم سوشي بالقرب مني\"",
      ru: "Привет, я Сяосюн, помогу вам найти рестораны; например: «суши-рестораны рядом со мной»",
    };
    return welcomes[i18n.language] || welcomes.en;
  };

  return (
    <div className={cn("flex flex-col h-full bg-background overflow-hidden", className)}>
      {/* Header - sticky to stay visible when iOS keyboard appears */}
      {showHeader && (
        <div className="px-4 py-3 shrink-0 border-b flex items-center gap-2 bg-background sticky top-0 z-10">
          {showBackButton && (
            <Button
              variant="ghost"
              size="icon"
              onClick={onClose}
              className="shrink-0"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
          )}
          <div className="flex items-center gap-2 flex-1">
            {logoUrl && <img src={logoUrl} alt="Logo" className="w-8 h-8 rounded-full object-cover" />}
            <h1 className="text-base font-semibold">{getTitle()}</h1>
          </div>
          {messages.length > 0 && onClearChat && (
            <button
              onClick={handleClearAndNewChat}
              className="p-1 hover:bg-muted rounded-md text-muted-foreground hover:text-primary transition-colors"
              title={t("aiRecipe.newChat", "新对话")}
            >
              <SquarePen className="h-4 w-4" />
            </button>
          )}
        </div>
      )}

      {/* Chat Messages Area */}
      <ScrollArea className="flex-1 min-h-0 overflow-auto" ref={scrollAreaRef}>
        <div className="p-4 space-y-4">
          {/* Welcome message */}
          {messages.length === 0 && (
            <div className="flex gap-3">
              <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center shrink-0 overflow-hidden">
                {logoUrl && <img src={logoUrl} alt="Xiaoxiong" className="w-full h-full object-cover" />}
              </div>
              <div className="flex-1 bg-muted rounded-lg px-3 py-2 text-sm">
                {getWelcomeMessage()}
              </div>
            </div>
          )}

          {/* Messages */}
          {messages.map((message) => {
            const recipes = message.role === "assistant" ? extractRecipes(message.content) : [];
            const displayContent = message.role === "assistant" ? stripRecipeJson(message.content) : message.content;
            const msgImageMap = recipeImages[message.id];

            return (
            <div key={message.id} className="space-y-2">
            <div
              className={cn(
                "flex gap-3",
                message.role === "user" && "flex-row-reverse"
              )}
            >
              {message.role === "user" ? (
                <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center shrink-0 overflow-hidden">
                  {userAvatarUrl ? (
                    <img src={userAvatarUrl} alt="User" className="w-full h-full object-cover" />
                  ) : (
                    <User className="h-4 w-4" />
                  )}
                </div>
              ) : (
                <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center shrink-0 overflow-hidden">
                  {logoUrl && <img src={logoUrl} alt="Xiaoxiong" className="w-full h-full object-cover" />}
                </div>
              )}
              <div
                className={cn(
                  "flex-1 max-w-[85%] rounded-lg px-3 py-2 text-sm bg-muted",
                )}
              >
                {message.role === "assistant" ? (
                  <>
                    {displayContent ? (
                      <div className="prose-sm">
                        {renderMarkdown(displayContent)}
                      </div>
                    ) : (
                      <div className="flex items-center gap-2 text-muted-foreground">
                        <Loader2 className="h-4 w-4 animate-spin" />
                        <span>
                          {i18n.language === "zh"
                            ? "思考中..."
                            : i18n.language === "pt"
                            ? "Pensando..."
                            : "Thinking..."}
                        </span>
                      </div>
                    )}
                    {message.isStreaming && displayContent && (
                      <span className="inline-block w-1.5 h-4 bg-primary/50 animate-pulse ml-0.5 align-middle" />
                    )}
                  </>
                ) : (
                  message.content
                )}
              </div>
            </div>

            {/* Recipe cards */}
            {recipes.length > 0 && (
              <div className="pl-11 space-y-2 max-w-[85%]">
                {recipes.map((recipe, ri) => {
                  const imgState = msgImageMap?.[recipe.recipe_name];
                  const isImgLoading = imgState?.loading ?? false;
                  const imageUrl = imgState?.url ?? null;
                  const recipeName = i18n.language === "en" && recipe.recipe_name_en
                    ? recipe.recipe_name_en
                    : i18n.language === "pt" && (recipe as any).recipe_name_pt
                    ? (recipe as any).recipe_name_pt
                    : recipe.recipe_name;

                  return (
                    <div
                      key={ri}
                      className="rounded-xl border border-border overflow-hidden cursor-pointer hover:border-primary/50 transition-colors bg-background"
                      onClick={() => handleViewRecipe(recipe, message.id)}
                    >
                      <div className="relative w-full aspect-[16/9] bg-muted overflow-hidden">
                        {isImgLoading ? (
                          <>
                            <Skeleton className="absolute inset-0 w-full h-full rounded-none" />
                            <div className="absolute inset-0 flex flex-col items-center justify-center gap-1.5 z-10">
                              <Sparkles className="h-4 w-4 text-primary animate-pulse" />
                              <span className="text-[10px] text-muted-foreground">
                                {t("aiRecipe.generatingImage", "AI 正在生成图片...")}
                              </span>
                            </div>
                          </>
                        ) : imageUrl ? (
                          <>
                            <img src={imageUrl} alt={recipeName} className="w-full h-full object-cover" loading="lazy" />
                            <div className="absolute bottom-1.5 right-1.5">
                              <span className="inline-flex items-center gap-1 text-[10px] bg-black/50 text-white px-1.5 py-0.5 rounded-full">
                                <Sparkles className="h-2.5 w-2.5" />AI
                              </span>
                            </div>
                          </>
                        ) : (
                          <div className="absolute inset-0 flex items-center justify-center">
                            <Image className="h-8 w-8 text-muted-foreground/30" />
                          </div>
                        )}
                      </div>
                      <div className="px-3 py-2.5 space-y-1.5">
                        <p className="font-semibold text-sm leading-tight">{recipeName}</p>
                        <div className="flex items-center gap-2 flex-wrap">
                          {recipe.cook_time && (
                            <Badge variant="outline" className="gap-1 text-[10px] h-5 px-1.5">
                              <Clock className="h-2.5 w-2.5" />
                              {recipe.cook_time} {t("recipe.minutes", "分钟")}
                            </Badge>
                          )}
                          {recipe.servings && (
                            <Badge variant="outline" className="gap-1 text-[10px] h-5 px-1.5">
                              <Users className="h-2.5 w-2.5" />
                              {recipe.servings} {t("recipe.servingsUnit", "人份")}
                            </Badge>
                          )}
                        </div>
                        <div className="flex gap-2 pt-0.5" onClick={(e) => e.stopPropagation()}>
                          <Button variant="outline" size="sm" className="gap-1.5 h-7 text-xs flex-1" onClick={() => handleViewRecipe(recipe, message.id)}>
                            <Utensils className="h-3 w-3" />
                            {t("aiRecipe.viewRecipe", "查看食谱")}
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            className={`gap-1 h-7 text-xs ${isRecipeSaved(recipe) ? "text-primary" : "text-muted-foreground"}`}
                            onClick={() => handleSaveRecipe(recipe)}
                            disabled={isSaving || isRecipeSaved(recipe)}
                          >
                            <Bookmark className={`h-3 w-3 ${isRecipeSaved(recipe) ? "fill-primary" : ""}`} />
                            {isRecipeSaved(recipe) ? t("aiRecipe.saved", "已保存") : t("aiRecipe.save", "保存")}
                          </Button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
            </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>
      </ScrollArea>

      {/* Input Section */}
      <div className="px-2 py-1.5 pb-[max(1.5rem,calc(env(safe-area-inset-bottom)+1rem))] md:pb-4 shrink-0">
        <div className="flex items-center gap-1.5 px-2 py-1.5 rounded-full backdrop-blur-md border border-border/50 bg-muted/80 dark:bg-muted/60">
          {shouldShowVoiceInput() && (
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleListening}
              disabled={isLoading}
              className={cn("bg-transparent hover:bg-transparent", isListening && "text-destructive")}
            >
              {isListening ? <MicOff className="h-4 w-4" /> : <Mic className="h-4 w-4" />}
            </Button>
          )}
          
          <Input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={isListening ? (i18n.language === "zh" ? "正在聆听..." : "Listening...") : getPlaceholder()}
            disabled={isLoading}
            className="flex-1 bg-transparent border-0 shadow-none focus-visible:ring-0 focus-visible:ring-offset-0"
          />
          <Button
            onClick={handleSubmit}
            disabled={!input.trim() || isLoading}
            size="icon"
            variant="ghost"
            className="bg-transparent hover:bg-white/50 rounded-full"
          >
            {isLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
          </Button>
        </div>
      </div>

      {/* Location Permission Dialog */}
      <LocationPermissionDialog
        open={showLocationDialog}
        onOpenChange={(open) => {
          setShowLocationDialog(open);
          if (!open && pendingMessage) {
            processMessage(pendingMessage);
            setPendingMessage(null);
          }
        }}
        onConfirm={handleLocationConfirm}
      />

      {/* External Link Confirm Dialog */}
      <ExternalLinkConfirmDialog
        open={externalLinkDialogOpen}
        onOpenChange={setExternalLinkDialogOpen}
        onConfirm={confirmExternalLink}
        url={pendingExternalLink || undefined}
      />


      {/* Recipe preview dialog */}
      <SavedRecipeDetailDialog
        open={previewOpen}
        onOpenChange={setPreviewOpen}
        recipe={previewRecipe}
        recipeName={previewRecipe?.recipe_name || ""}
        onSave={handleSaveRecipe}
        isSaving={isSaving}
        isSaved={previewRecipe ? isRecipeSaved(previewRecipe) : false}
        initialImageUrl={previewImageUrl}
        enableVideoGeneration
      />
    </div>
  );
};

export default XiaoxiongChatContent;
